button.description:
## Description

Bouton d'action principal du Design System, disponible en 4 variantes, 3 tailles et 5 états.

## Spec

- **Variantes** : `primary`, `secondary`, `ghost`, `danger`
- **Tailles** : `sm` (padding 4px 16px, font 14px), `md` (padding 8px 16px, font 16px), `lg` (padding 8px 24px, font 18px)
- **États** : `default`, `hover`, `active`, `focus`, `disabled` — focus ring issu des tokens `--button-focus-ring-*` (pas de variante Figma explicite pour focus)
- **Rayon** : `var(--button-radius, 8px)` uniforme sur toutes les tailles et variantes
- **Icônes** : optionnelles gauche/droite, `12px × 12px`, gap piloté par `--button-size-{size}-gap`
- **Accessibilité** : élément `<button>` natif, `disabled` attribut natif, focus visible préservé

## Do & Don't

**Do**
- Utiliser `primary` pour l'action dominante d'une zone.
- Spécifier explicitement `type="button"`, `type="submit"` ou `type="reset"`.
- Utiliser `disabled` natif pour l'état désactivé.

**Don't**
- Ne pas utiliser un `<button>` pour la navigation : préférer un `<a>` dans ce cas.
- Ne pas inventer de variantes hors `primary`, `secondary`, `ghost`, `danger`.

## Code interactif (Live Editor)

```jsx
const VARIANTS = ['primary', 'secondary', 'ghost', 'danger'];
const SIZES = ['sm', 'md', 'lg'];
const STATES = ['default', 'hover', 'active', 'focus', 'disabled'];

const colorVar = (variant, part, state, fallback) =>
  `var(--color-action-${variant}-${part}-${state}, ${fallback})`;

const sizeVar = (size, part, fallback) =>
  `var(--button-size-${size}-${part}, ${fallback})`;

const SIZE_FALLBACKS = {
  sm: { paddingX: '16px', paddingY: '4px', fontSize: '14px', lineHeight: '17px', gap: '4px', minHeight: '25px' },
  md: { paddingX: '16px', paddingY: '8px', fontSize: '16px', lineHeight: '19px', gap: '8px', minHeight: '35px' },
  lg: { paddingX: '24px', paddingY: '8px', fontSize: '18px', lineHeight: '22px', gap: '8px', minHeight: '38px' },
};

const COLOR_FALLBACKS = {
  primary:   { bg: { default:'#368e35', hover:'#1D4ED8', active:'#1E40AF', focus:'#368e35', disabled:'#F3F4F6' }, text: { default:'#FFFFFF', hover:'#FFFFFF', active:'#FFFFFF', focus:'#FFFFFF', disabled:'#D1D5DB' }, border: { default:'#368e35', hover:'#1D4ED8', active:'#1E40AF', focus:'#368e35', disabled:'#F3F4F6' } },
  secondary: { bg: { default:'#FFFFFF', hover:'#F9FAFB', active:'#F3F4F6', focus:'#FFFFFF', disabled:'#F9FAFB' }, text: { default:'#374151', hover:'#374151', active:'#374151', focus:'#374151', disabled:'#D1D5DB' }, border: { default:'#D1D5DB', hover:'#9CA3AF', active:'#D1D5DB', focus:'#D1D5DB', disabled:'#E5E7EB' } },
  ghost:     { bg: { default:'transparent', hover:'#F3F4F6', active:'#E5E7EB', focus:'transparent', disabled:'transparent' }, text: { default:'#374151', hover:'#1f2937', active:'#374151', focus:'#374151', disabled:'#D1D5DB' }, border: { default:'transparent', hover:'transparent', active:'transparent', focus:'transparent', disabled:'transparent' } },
  danger:    { bg: { default:'#DC2626', hover:'#B91C1C', active:'#991B1B', focus:'#DC2626', disabled:'#F3F4F6' }, text: { default:'#FFFFFF', hover:'#FFFFFF', active:'#FFFFFF', focus:'#FFFFFF', disabled:'#D1D5DB' }, border: { default:'#DC2626', hover:'#B91C1C', active:'#991B1B', focus:'#DC2626', disabled:'#F3F4F6' } },
};

function Button({ variant = 'primary', size = 'md', state = 'default', children = 'Button' }) {
  const sf = SIZE_FALLBACKS[size];
  const cf = COLOR_FALLBACKS[variant];
  const isDisabled = state === 'disabled';
  const isFocus = state === 'focus';

  const style = {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: sizeVar(size, 'gap', sf.gap),
    minHeight: sizeVar(size, 'min-height', sf.minHeight),
    padding: `${sizeVar(size, 'padding-y', sf.paddingY)} ${sizeVar(size, 'padding-x', sf.paddingX)}`,
    fontSize: sizeVar(size, 'font-size', sf.fontSize),
    lineHeight: sizeVar(size, 'line-height', sf.lineHeight),
    fontFamily: `var(--button-font-family, Inter, sans-serif)`,
    fontWeight: `var(--button-font-weight, 600)`,
    borderRadius: `var(--button-radius, 8px)`,
    borderWidth: `var(--button-border-width, 1px)`,
    borderStyle: 'solid',
    backgroundColor: colorVar(variant, 'bg', state, cf.bg[state]),
    color: colorVar(variant, 'text', state, cf.text[state]),
    borderColor: colorVar(variant, 'border', state, cf.border[state]),
    cursor: isDisabled ? 'not-allowed' : 'pointer',
    outline: isFocus
      ? `var(--button-focus-ring-width, 2px) solid var(--button-focus-ring-color, #368e35)`
      : 'none',
    outlineOffset: isFocus ? `var(--button-focus-ring-offset, 2px)` : undefined,
    transition: `var(--button-transition, all 0.15s ease)`,
    boxSizing: 'border-box',
  };

  return (
    <button type="button" disabled={isDisabled} style={style}>
      {children}
    </button>
  );
}

function Demo() {
  const labelMap = { default: 'Default', hover: 'Hover', active: 'Active', focus: 'Focus', disabled: 'Disabled' };
  const cellStyle = { display: 'flex', flexDirection: 'column', alignItems: 'flex-start', gap: '6px' };
  const headerStyle = { fontSize: '11px', fontFamily: 'Inter, sans-serif', color: '#6B7280', fontWeight: 600, marginBottom: '2px', textTransform: 'uppercase', letterSpacing: '0.05em' };
  const variantLabelStyle = { fontSize: '11px', fontFamily: 'Inter, sans-serif', color: '#374151', fontWeight: 700, width: '80px', display: 'flex', alignItems: 'center', minHeight: '20px', textTransform: 'capitalize' };

  return (
    <div style={{ padding: '24px', background: '#F9FAFB', fontFamily: 'Inter, sans-serif' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '80px repeat(5, auto)', gap: '12px', alignItems: 'start' }}>
        <div />
        {STATES.map(s => (
          <div key={s} style={headerStyle}>{labelMap[s]}</div>
        ))}
        {VARIANTS.map(variant => (
          <>
            <div key={`label-${variant}`} style={variantLabelStyle}>{variant}</div>
            {STATES.map(state => (
              <div key={`${variant}-${state}`} style={cellStyle}>
                {SIZES.map(size => (
                  <Button key={size} variant={variant} size={size} state={state}>
                    {size.toUpperCase()}
                  </Button>
                ))}
              </div>
            ))}
          </>
        ))}
      </div>
    </div>
  );
}

render(<Demo />);
```
